sys_script_include.script:
var PlantCareUtils = Class.create();
PlantCareUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getCareDetails: function() {
        var profileId = this.getParameter('sysparm_care_profile');

        var result = {
            sunlight: '',
            watering_frequency: ''
        };

        if (!profileId) {
            return JSON.stringify(result);
        }

        var profile = new GlideRecord('x_1840724_plant_0_plant_care_profile');
        if (profile.get(profileId)) {
            result.sunlight = profile.getValue('sunlight');
            result.watering_frequency = profile.getValue('watering_frequency');
        }

        return JSON.stringify(result);
    },

    type: 'PlantCareUtils'
});
